import React from "react"
import Posts from "./components/Posts"
import Header from "./components/Header"
import AddPost from "./components/AddPost"
import {Routes, Route, Link} from "react-router-dom"
// import axios from "axios"


class App extends React.Component {
    render() {
        return (<div>
            <Header />
            <Posts users={this.state.users} onDelete={this.deleteUser} onEdit={this.editUser} />
            <aside>
                <AddPost onAdd={this.addUser} />
            </aside>
        </div>)
    }
    addUser(user) {
        const id = this.state.users.length + 1;
        this.setState({
            users: [...this.state.users, {id, ...user}]
        })
    }
    editUser(user) {
        const newMass = this.state.users
        newMass[user.id - 1] = user
        this.setState({users: newMass})
    }
    deleteUser(id) {
        const newMass = [...this.state.users.slice(0, id - 1), ...this.state.users.slice(id, this.state.users.length)]
        for (let i = 0; i < newMass.length; i++) {
            newMass[i].id = i + 1
        }
        this.setState({
            users: newMass
        })
    }
}



export default App
